import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { PiggyBank, Plus, AlertCircle } from 'lucide-react';
import '../styles/Orcamento.css';

const Orcamento = () => {
  const [loading, setLoading] = useState(true);
  const [perfil, setPerfil] = useState(null);
  
  // Dados mockados (você pode substituir por uma chamada ao Supabase depois)
  const [dados, setDados] = useState({
    metaGlobal: 8000,
    gastoAtual: 5400,
    categorias: [
      { nome: 'Moradia', gasto: 2500, meta: 2500, cor: '#4361ee' },
      { nome: 'Alimentação', gasto: 1800, meta: 1500, cor: '#7209b7' },
      { nome: 'Transporte', gasto: 600, meta: 1000, cor: '#4cc9f0' },
      { nome: 'Lazer', gasto: 500, meta: 400, cor: '#f72585' }
    ]
  });

  useEffect(() => {
    verificarAcesso();
  }, []);

  async function verificarAcesso() {
    setLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      const { data: perfilData } = await supabase.from('profiles')
        .select('*')
        .eq('id', user.id)
        .single();

      const isMaster = user.email === 'gleidson.fig@gmail.com';
      
      if (perfilData?.tipo_usuario === 'proprietario' || isMaster) {
        setPerfil(perfilData);
      } else {
        // Se não for proprietário, redireciona para o Dashboard comum
        window.location.href = '/dashboard';
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }

  const formatMoney = (v) => v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  const porcGlobal = (dados.gastoAtual / dados.metaGlobal) * 100;

  if (loading) return <div className="loading-state">Carregando Orçamento...</div>;

  return (
    <div className="orcamento-container fade-in">
      <header className="orcamento-header">
        <div>
          <h2>Orçamento Mensal</h2>
          <p>Controle de metas e limites de gastos</p>
        </div>
        <button className="btn-novo-orcamento">
          <Plus size={20} /> Definir Meta
        </button>
      </header>

      {/* Card de Progresso Geral */}
      <section className="meta-global-card">
        <div className="meta-info">
          <div className="meta-text">
            <span>Uso do Orçamento Global</span>
            <h3>
              {formatMoney(dados.gastoAtual)} 
              <small> / {formatMoney(dados.metaGlobal)}</small>
            </h3>
          </div>
          <PiggyBank size={48} color="#4361ee" opacity={0.2} />
        </div>
        
        <div className="progress-bar-container">
          <div 
            className={`progress-bar-fill ${porcGlobal > 100 ? 'over-limit' : ''}`}
            style={{ width: `${Math.min(porcGlobal, 100)}%` }}
          />
        </div>
        <span className="progress-label">
          {porcGlobal.toFixed(1)}% utilizado
        </span>
      </section>

      {/* Grid de Categorias */}
      <div className="orcamento-grid">
        {dados.categorias.map((cat, i) => {
          const porc = (cat.gasto / cat.meta) * 100;
          const excedeu = cat.gasto > cat.meta;

          return (
            <div key={i} className="categoria-card">
              <div className="categoria-header">
                <span className="categoria-nome">{cat.nome}</span>
                {excedeu && <AlertCircle size={18} color="#ef4444" />}
              </div>
              
              <div className="categoria-valores">
                <span className="valor-gasto">{formatMoney(cat.gasto)}</span>
                <span className="valor-meta">Meta: {formatMoney(cat.meta)}</span>
              </div>

              <div className="mini-progress-bg">
                <div 
                  className="mini-progress-fill"
                  style={{ 
                    width: `${Math.min(porc, 100)}%`,
                    backgroundColor: excedeu ? '#ef4444' : cat.cor
                  }}
                />
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Orcamento;
